import type { Quiz, QuestionAttemptResult } from './types/quiz';
import { renderHomeScreen } from './components/home-screen';
import { renderQuizPlayer } from './components/quiz-player';
import { renderResultsScreen, calculateResult, saveResult } from './components/results-screen';
import { renderStatsScreen } from './components/stats-screen';
import { renderQuizCreator } from './components/quiz-creator';
import { saveCustomQuiz, updateCustomQuiz } from './storage/custom-quizzes';
import { saveQuizProgress, loadQuizProgress, clearQuizProgress } from './storage/quiz-progress';
import { renderDataManagement } from './components/data-management';

/**
 * Initialize the application and mount it to the given root element.
 * Manages navigation between home, quiz player, results, stats, and creator screens.
 */
export function createApp(root: HTMLElement): void {
  showHome(root);
}

function showHome(root: HTMLElement): void {
  root.innerHTML = '';
  renderHomeScreen(
    root,
    (quiz: Quiz) => { showQuiz(root, quiz); },
    () => { showStats(root); },
    () => { showCreator(root); },
    () => { showDataManagement(root); },
  );
}

function showStats(root: HTMLElement): void {
  root.innerHTML = '';
  renderStatsScreen(root, () => { showHome(root); });
}

function showQuiz(root: HTMLElement, quiz: Quiz): void {
  root.innerHTML = '';

  // Restore saved progress if available
  const saved = loadQuizProgress(quiz.id);
  const initialState = saved ? { currentIndex: saved.currentIndex, questions: saved.questions } : undefined;

  renderQuizPlayer(
    root,
    quiz,
    (attemptResults: QuestionAttemptResult[]) => {
      clearQuizProgress(quiz.id);
      const result = calculateResult(quiz, attemptResults);
      saveResult(result);
      showResults(root, quiz, result, attemptResults);
    },
    () => { showHome(root); },
    initialState,
    (currentIndex, questions) => {
      saveQuizProgress({
        quizId: quiz.id,
        currentIndex,
        questions,
        savedAt: Date.now(),
      });
    },
  );
}

function showResults(
  root: HTMLElement,
  quiz: Quiz,
  result: ReturnType<typeof calculateResult>,
  attemptResults: QuestionAttemptResult[],
): void {
  root.innerHTML = '';
  renderResultsScreen(
    root,
    quiz,
    result,
    () => { showQuiz(root, quiz); },
    () => { showHome(root); },
    attemptResults,
  );
}

function showDataManagement(root: HTMLElement): void {
  root.innerHTML = '';
  renderDataManagement(
    root,
    () => { showHome(root); },
    (quiz: Quiz) => { showCreatorEdit(root, quiz); },
  );
}

function showCreator(root: HTMLElement): void {
  root.innerHTML = '';
  renderQuizCreator(
    root,
    () => { showHome(root); },
    (quiz: Quiz) => {
      saveCustomQuiz(quiz);
      showHome(root);
    },
  );
}

function showCreatorEdit(root: HTMLElement, existingQuiz: Quiz): void {
  root.innerHTML = '';
  renderQuizCreator(
    root,
    () => { showDataManagement(root); },
    (quiz: Quiz) => {
      updateCustomQuiz(quiz);
      showDataManagement(root);
    },
    existingQuiz,
  );
}
