import type { Quiz, QuizQuestion, AnswerOption } from '../types/quiz';

/** Callback when user exits the creator. */
export type OnCreatorExit = () => void;

/** Callback when a quiz is successfully created. */
export type OnQuizCreated = (quiz: Quiz) => void;

interface QuestionFormData {
  questionText: string;
  answers: string[];
  correctIndex: number;
  explanation: string;
}

interface QuestionFormRefs {
  card: HTMLElement;
  questionInput: HTMLInputElement;
  answerInputs: HTMLInputElement[];
  radioInputs: HTMLInputElement[];
  explanationInput: HTMLInputElement;
  textError: HTMLElement;
  answersError: HTMLElement;
  correctError: HTMLElement;
  numberEl: HTMLElement;
}

/** Generate a unique ID based on timestamp and random suffix. */
export function generateId(): string {
  const timestamp = Date.now().toString(36);
  const random = Math.random().toString(36).slice(2, 8);
  return `${timestamp}-${random}`;
}

/** Validate the quiz form data and return error messages by field. */
export function validateQuizForm(
  title: string,
  questions: QuestionFormData[],
): Map<string, string> {
  const errors = new Map<string, string>();

  if (title.trim() === '') {
    errors.set('title', 'N\u00E1zev kv\u00EDzu je povinn\u00FD');
  }

  if (questions.length === 0) {
    errors.set('questions', 'P\u0159idejte alespo\u0148 jednu ot\u00E1zku');
  }

  for (let i = 0; i < questions.length; i++) {
    const q = questions[i];
    const prefix = `question-${String(i)}`;

    if (q.questionText.trim() === '') {
      errors.set(`${prefix}-text`, 'Text ot\u00E1zky je povinn\u00FD');
    }

    const filledAnswers = q.answers.filter((a) => a.trim() !== '');
    if (filledAnswers.length < 2) {
      errors.set(`${prefix}-answers`, 'Vypl\u0148te alespo\u0148 2 odpov\u011Bdi');
    }

    if (q.correctIndex === -1) {
      errors.set(`${prefix}-correct`, 'Vyberte spr\u00E1vnou odpov\u011B\u010F');
    } else if (q.correctIndex >= 0 && q.answers[q.correctIndex].trim() === '') {
      errors.set(`${prefix}-correct`, 'Spr\u00E1vn\u00E1 odpov\u011B\u010F nesm\u00ED b\u00FDt pr\u00E1zdn\u00E1');
    }
  }

  return errors;
}

/** Build a Quiz object from validated form data. */
export function buildQuiz(
  title: string,
  description: string,
  questions: QuestionFormData[],
  existingId?: string,
): Quiz {
  const quizId = existingId ?? `custom-${generateId()}`;

  const quizQuestions: QuizQuestion[] = questions.map((q, qIndex) => {
    const answers: AnswerOption[] = q.answers
      .map((text, aIndex) => ({
        id: `a${String(aIndex)}`,
        text: text.trim(),
        isCorrect: aIndex === q.correctIndex,
      }))
      .filter((a) => a.text !== '');

    return {
      id: `${quizId}-q${String(qIndex)}`,
      question: q.questionText.trim(),
      answers,
      ...(q.explanation.trim() !== '' ? { explanation: q.explanation.trim() } : {}),
    };
  });

  return {
    id: quizId,
    title: title.trim(),
    description: description.trim(),
    grade: 0,
    subject: '',
    topic: '',
    questions: quizQuestions,
  };
}

/** Render the quiz creator form into the given container. */
export function renderQuizCreator(
  container: HTMLElement,
  onExit: OnCreatorExit,
  onQuizCreated: OnQuizCreated,
  existingQuiz?: Quiz,
): void {
  const isEditMode = existingQuiz !== undefined;

  const wrapper = document.createElement('div');
  wrapper.className = 'quiz-creator';

  // Header
  const header = document.createElement('div');
  header.className = 'creator-header';

  const backBtn = document.createElement('button');
  backBtn.className = 'btn btn-ghost quiz-exit-btn';
  backBtn.textContent = '\u2190 Zp\u011Bt';
  backBtn.addEventListener('click', () => { onExit(); });

  const title = document.createElement('h1');
  title.className = 'creator-title';
  title.textContent = isEditMode ? 'Upravit kv\u00EDz' : 'Vytvo\u0159it kv\u00EDz';

  const subtitle = document.createElement('p');
  subtitle.className = 'creator-subtitle';
  subtitle.textContent = isEditMode ? 'Uprav sv\u016Fj kv\u00EDz' : 'P\u0159idej si vlastn\u00ED ot\u00E1zky';

  header.appendChild(backBtn);
  header.appendChild(title);
  header.appendChild(subtitle);

  // Quiz info fields
  const titleInput = document.createElement('input');
  titleInput.type = 'text';
  titleInput.className = 'creator-input';
  titleInput.id = 'quiz-title';
  titleInput.placeholder = 'Nap\u0159. Matematika 5. t\u0159\u00EDda';
  if (existingQuiz) {
    titleInput.value = existingQuiz.title;
  }

  const titleError = document.createElement('div');
  titleError.className = 'creator-error';

  const titleField = createField('N\u00E1zev kv\u00EDzu', 'quiz-title', titleInput, titleError);

  const descInput = document.createElement('input');
  descInput.type = 'text';
  descInput.className = 'creator-input';
  descInput.id = 'quiz-desc';
  descInput.placeholder = 'Voliteln\u00FD popis kv\u00EDzu';
  if (existingQuiz) {
    descInput.value = existingQuiz.description;
  }

  const descField = createField('Popis', 'quiz-desc', descInput);

  // Questions container
  const questionsContainer = document.createElement('div');
  questionsContainer.className = 'creator-questions';

  // Track question forms
  const questionRefs: QuestionFormRefs[] = [];

  function addQuestionForm(prefill?: QuizQuestion): void {
    const index = questionRefs.length;
    const refs = createQuestionCard(index, () => {
      if (questionRefs.length <= 1) return;
      refs.card.remove();
      questionRefs.splice(questionRefs.indexOf(refs), 1);
      renumberQuestions();
    });

    if (prefill) {
      refs.questionInput.value = prefill.question;
      for (let i = 0; i < prefill.answers.length && i < refs.answerInputs.length; i++) {
        refs.answerInputs[i].value = prefill.answers[i].text;
        if (prefill.answers[i].isCorrect) {
          refs.radioInputs[i].checked = true;
        }
      }
      if (prefill.explanation) {
        refs.explanationInput.value = prefill.explanation;
      }
    }

    questionRefs.push(refs);
    questionsContainer.appendChild(refs.card);
  }

  function renumberQuestions(): void {
    for (const [i, refs] of questionRefs.entries()) {
      refs.numberEl.textContent = `Ot\u00E1zka ${String(i + 1)}`;
    }
  }

  // Add questions — pre-fill from existing quiz or start with one empty
  if (existingQuiz && existingQuiz.questions.length > 0) {
    for (const q of existingQuiz.questions) {
      addQuestionForm(q);
    }
  } else {
    addQuestionForm();
  }

  // Add question button
  const addBtn = document.createElement('button');
  addBtn.className = 'btn btn-ghost creator-add-btn';
  addBtn.textContent = '+ P\u0159idat ot\u00E1zku';
  addBtn.addEventListener('click', () => { addQuestionForm(); });

  // Save button
  const saveBtn = document.createElement('button');
  saveBtn.className = 'btn btn-success';
  saveBtn.textContent = 'Ulo\u017Eit kv\u00EDz';
  saveBtn.addEventListener('click', () => {
    handleSave(titleInput, titleError, descInput, questionRefs, onQuizCreated, existingQuiz?.id);
  });

  wrapper.appendChild(header);
  wrapper.appendChild(titleField);
  wrapper.appendChild(descField);
  wrapper.appendChild(questionsContainer);
  wrapper.appendChild(addBtn);
  wrapper.appendChild(saveBtn);

  container.appendChild(wrapper);
}

function createField(
  labelText: string,
  inputId: string,
  input: HTMLInputElement,
  error?: HTMLElement,
): HTMLElement {
  const field = document.createElement('div');
  field.className = 'creator-field';

  const labelEl = document.createElement('label');
  labelEl.className = 'creator-label';
  labelEl.htmlFor = inputId;
  labelEl.textContent = labelText;

  field.appendChild(labelEl);
  field.appendChild(input);

  if (error) {
    field.appendChild(error);
  }

  return field;
}

function createQuestionCard(index: number, onRemove: () => void): QuestionFormRefs {
  const card = document.createElement('div');
  card.className = 'creator-question-card';

  // Header with number and remove button
  const headerRow = document.createElement('div');
  headerRow.className = 'creator-question-header';

  const numberEl = document.createElement('span');
  numberEl.className = 'creator-question-number';
  numberEl.textContent = `Ot\u00E1zka ${String(index + 1)}`;

  const removeBtn = document.createElement('button');
  removeBtn.className = 'btn btn-ghost creator-remove-btn';
  removeBtn.textContent = '\u00D7';
  removeBtn.addEventListener('click', () => { onRemove(); });

  headerRow.appendChild(numberEl);
  headerRow.appendChild(removeBtn);

  // Question text
  const questionInput = document.createElement('input');
  questionInput.type = 'text';
  questionInput.className = 'creator-input creator-question-input';
  questionInput.placeholder = 'Zn\u011Bn\u00ED ot\u00E1zky';

  const textError = document.createElement('div');
  textError.className = 'creator-error';

  // Answer fields
  const answersContainer = document.createElement('div');
  answersContainer.className = 'creator-answers';

  const radioName = `correct-${String(index)}-${Date.now().toString(36)}`;

  const answerInputs: HTMLInputElement[] = [];
  const radioInputs: HTMLInputElement[] = [];

  for (let i = 0; i < 4; i++) {
    const row = document.createElement('div');
    row.className = 'creator-answer-row';

    const radio = document.createElement('input');
    radio.type = 'radio';
    radio.name = radioName;
    radio.className = 'creator-radio';
    radio.value = String(i);
    radio.title = 'spr\u00E1vn\u00E1';

    const answerInput = document.createElement('input');
    answerInput.type = 'text';
    answerInput.className = 'creator-input creator-answer-input';
    answerInput.placeholder = `Odpov\u011B\u010F ${String.fromCharCode(65 + i)}`;

    row.appendChild(radio);
    row.appendChild(answerInput);
    answersContainer.appendChild(row);

    answerInputs.push(answerInput);
    radioInputs.push(radio);
  }

  const answersError = document.createElement('div');
  answersError.className = 'creator-error';

  const correctError = document.createElement('div');
  correctError.className = 'creator-error';

  // Explanation
  const explanationInput = document.createElement('input');
  explanationInput.type = 'text';
  explanationInput.className = 'creator-input creator-explanation-input';
  explanationInput.placeholder = 'Vysv\u011Btlen\u00ED (voliteln\u00E9)';

  card.appendChild(headerRow);
  card.appendChild(questionInput);
  card.appendChild(textError);
  card.appendChild(answersContainer);
  card.appendChild(answersError);
  card.appendChild(correctError);
  card.appendChild(explanationInput);

  return {
    card,
    questionInput,
    answerInputs,
    radioInputs,
    explanationInput,
    textError,
    answersError,
    correctError,
    numberEl,
  };
}

function extractFormData(questionRefs: QuestionFormRefs[]): QuestionFormData[] {
  return questionRefs.map((refs) => {
    let correctIndex = -1;
    for (const [i, radio] of refs.radioInputs.entries()) {
      if (radio.checked) {
        correctIndex = i;
      }
    }

    return {
      questionText: refs.questionInput.value,
      answers: refs.answerInputs.map((input) => input.value),
      correctIndex,
      explanation: refs.explanationInput.value,
    };
  });
}

function clearAllErrors(
  titleInput: HTMLInputElement,
  titleError: HTMLElement,
  questionRefs: QuestionFormRefs[],
): void {
  titleError.textContent = '';
  titleInput.classList.remove('invalid');

  for (const refs of questionRefs) {
    refs.textError.textContent = '';
    refs.answersError.textContent = '';
    refs.correctError.textContent = '';
    refs.questionInput.classList.remove('invalid');
  }
}

function displayErrors(
  titleInput: HTMLInputElement,
  titleError: HTMLElement,
  errors: Map<string, string>,
  questionRefs: QuestionFormRefs[],
): void {
  const titleErr = errors.get('title');
  if (titleErr) {
    titleError.textContent = titleErr;
    titleInput.classList.add('invalid');
  }

  for (let i = 0; i < questionRefs.length; i++) {
    const refs = questionRefs[i];
    const prefix = `question-${String(i)}`;

    const textErr = errors.get(`${prefix}-text`);
    if (textErr) {
      refs.textError.textContent = textErr;
      refs.questionInput.classList.add('invalid');
    }

    const answersErr = errors.get(`${prefix}-answers`);
    if (answersErr) {
      refs.answersError.textContent = answersErr;
    }

    const correctErr = errors.get(`${prefix}-correct`);
    if (correctErr) {
      refs.correctError.textContent = correctErr;
    }
  }
}

function handleSave(
  titleInput: HTMLInputElement,
  titleError: HTMLElement,
  descInput: HTMLInputElement,
  questionRefs: QuestionFormRefs[],
  onQuizCreated: OnQuizCreated,
  existingId?: string,
): void {
  clearAllErrors(titleInput, titleError, questionRefs);

  const titleValue = titleInput.value;
  const descValue = descInput.value;

  const questionsData = extractFormData(questionRefs);
  const errors = validateQuizForm(titleValue, questionsData);

  if (errors.size > 0) {
    displayErrors(titleInput, titleError, errors, questionRefs);
    return;
  }

  const quiz = buildQuiz(titleValue, descValue, questionsData, existingId);
  onQuizCreated(quiz);
}
