import type { QuestionState } from '../components/quiz-player';
import { save, load, remove } from './local-storage';

const PROGRESS_PREFIX = 'progress_';

/** Saved state of an in-progress quiz. */
export interface SavedQuizProgress {
  quizId: string;
  currentIndex: number;
  questions: Partial<Record<string, QuestionState>>;
  savedAt: number;
}

/** Save quiz progress for later resumption. */
export function saveQuizProgress(progress: SavedQuizProgress): void {
  save(PROGRESS_PREFIX + progress.quizId, progress);
}

/** Load saved quiz progress. Returns null if none exists. */
export function loadQuizProgress(quizId: string): SavedQuizProgress | null {
  return load<SavedQuizProgress>(PROGRESS_PREFIX + quizId);
}

/** Clear saved progress for a quiz (e.g., after completion). */
export function clearQuizProgress(quizId: string): void {
  remove(PROGRESS_PREFIX + quizId);
}

/** Clear all saved quiz progress. */
export function clearAllProgress(): void {
  const allKeys = [];
  for (let i = 0; i < localStorage.length; i++) {
    const key = localStorage.key(i);
    if (key?.startsWith('featcher_' + PROGRESS_PREFIX)) {
      allKeys.push(key);
    }
  }
  for (const key of allKeys) {
    localStorage.removeItem(key);
  }
}
