import type { Quiz } from '../types/quiz';
import { quizRegistry } from '../content/registry';
import { loadCustomQuizzes } from '../storage/custom-quizzes';
import { loadQuizProgress } from '../storage/quiz-progress';
import { loadResults } from './results-screen';

/** Callback when user selects a quiz to play. */
export type OnQuizSelect = (quiz: Quiz) => void;

/** Callback when user wants to see statistics. */
export type OnShowStats = () => void;

/** Callback when user clicks the create quiz button. */
export type OnCreateQuiz = () => void;

/** Callback when user clicks the data management button. */
export type OnDataManagement = () => void;

/** Render the home screen with available quizzes. */
export function renderHomeScreen(
  container: HTMLElement,
  onQuizSelect: OnQuizSelect,
  onShowStats: OnShowStats,
  onCreateQuiz: OnCreateQuiz,
  onDataManagement?: OnDataManagement,
): void {
  const wrapper = document.createElement('div');
  wrapper.className = 'home-screen';

  const header = document.createElement('header');
  header.className = 'home-header';

  const title = document.createElement('h1');
  title.className = 'home-title';
  title.textContent = 'Featcher';

  const subtitle = document.createElement('p');
  subtitle.className = 'home-subtitle';
  subtitle.textContent = 'Teacher of the Future';

  const statsBtn = document.createElement('button');
  statsBtn.className = 'btn btn-ghost home-stats-btn';
  statsBtn.textContent = 'Statistiky';
  statsBtn.addEventListener('click', () => { onShowStats(); });

  header.appendChild(title);
  header.appendChild(subtitle);

  const headerActions = document.createElement('div');
  headerActions.className = 'home-header-actions';
  headerActions.appendChild(statsBtn);

  if (onDataManagement) {
    const dataBtn = document.createElement('button');
    dataBtn.className = 'btn btn-ghost home-data-btn';
    dataBtn.textContent = 'Správa dat';
    dataBtn.addEventListener('click', () => { onDataManagement(); });
    headerActions.appendChild(dataBtn);
  }

  header.appendChild(headerActions);

  wrapper.appendChild(header);

  const nav = document.createElement('nav');
  nav.className = 'quiz-list';

  const customQuizzes = loadCustomQuizzes();
  const allQuizzes = [...quizRegistry, ...customQuizzes];

  if (allQuizzes.length === 0) {
    const placeholder = document.createElement('p');
    placeholder.className = 'quiz-list-empty';
    placeholder.textContent = 'P\u0159ipravujeme kv\u00EDzy...';
    nav.appendChild(placeholder);
    wrapper.appendChild(nav);
  } else {
    let selectedGrade: number | null = null;
    let selectedSubject: string | null = null;
    const customIds = new Set(customQuizzes.map((q) => q.id));

    const renderQuizList = (): void => {
      nav.innerHTML = '';
      const filtered = allQuizzes.filter((quiz) => {
        if (selectedGrade !== null && quiz.grade !== selectedGrade) return false;
        if (selectedSubject !== null && quiz.subject !== selectedSubject) return false;
        return true;
      });

      if (filtered.length === 0) {
        const empty = document.createElement('p');
        empty.className = 'quiz-list-empty';
        empty.textContent = '\u017D\u00E1dn\u00E9 kv\u00EDzy pro tento v\u00FDb\u011Br';
        nav.appendChild(empty);
      } else {
        const results = loadResults();
        for (const quiz of filtered) {
          const isCustom = customIds.has(quiz.id);
          const card = createQuizCard(quiz, results, onQuizSelect, isCustom);
          nav.appendChild(card);
        }
      }
    };

    const filterBar = createFilterBar(allQuizzes, (grade, subject) => {
      selectedGrade = grade;
      selectedSubject = subject;
      renderQuizList();
    });

    wrapper.appendChild(filterBar);
    renderQuizList();
    wrapper.appendChild(nav);
  }

  // Create quiz button
  const createBtn = document.createElement('button');
  createBtn.className = 'btn btn-primary creator-home-btn';
  createBtn.textContent = 'Vytvo\u0159it kv\u00EDz';
  createBtn.addEventListener('click', () => { onCreateQuiz(); });

  wrapper.appendChild(createBtn);

  container.appendChild(wrapper);
}

function createFilterBar(
  quizzes: Quiz[],
  onFilterChange: (grade: number | null, subject: string | null) => void,
): HTMLElement {
  const bar = document.createElement('div');
  bar.className = 'filter-bar';

  let currentGrade: number | null = null;
  let currentSubject: string | null = null;

  // Grade dropdown
  const gradeSelect = document.createElement('select');
  gradeSelect.className = 'filter-select';

  const gradeAllOption = document.createElement('option');
  gradeAllOption.value = '';
  gradeAllOption.textContent = 'V\u0161echny ro\u010Dn\u00EDky';
  gradeSelect.appendChild(gradeAllOption);

  const grades = [...new Set(quizzes.map((q) => q.grade))].sort((a, b) => a - b);
  for (const grade of grades) {
    const option = document.createElement('option');
    option.value = String(grade);
    option.textContent = `${String(grade)}. ro\u010Dn\u00EDk`;
    gradeSelect.appendChild(option);
  }

  gradeSelect.addEventListener('change', () => {
    currentGrade = gradeSelect.value === '' ? null : Number(gradeSelect.value);
    onFilterChange(currentGrade, currentSubject);
  });

  // Subject dropdown
  const subjectSelect = document.createElement('select');
  subjectSelect.className = 'filter-select';

  const subjectAllOption = document.createElement('option');
  subjectAllOption.value = '';
  subjectAllOption.textContent = 'V\u0161echny p\u0159edm\u011Bty';
  subjectSelect.appendChild(subjectAllOption);

  const subjects = [...new Set(quizzes.map((q) => q.subject))].sort();
  for (const subject of subjects) {
    const option = document.createElement('option');
    option.value = subject;
    option.textContent = subject;
    subjectSelect.appendChild(option);
  }

  subjectSelect.addEventListener('change', () => {
    currentSubject = subjectSelect.value === '' ? null : subjectSelect.value;
    onFilterChange(currentGrade, currentSubject);
  });

  bar.appendChild(gradeSelect);
  bar.appendChild(subjectSelect);

  return bar;
}

function createQuizCard(
  quiz: Quiz,
  allResults: { quizId: string; score: number; totalQuestions: number; completedAt?: number }[],
  onQuizSelect: OnQuizSelect,
  isCustom: boolean,
): HTMLElement {
  const card = document.createElement('button');
  card.className = 'quiz-card';
  card.dataset.quizId = quiz.id;

  const info = document.createElement('div');
  info.className = 'quiz-card-info';

  const cardTitle = document.createElement('h3');
  cardTitle.className = 'quiz-card-title';
  cardTitle.textContent = quiz.title;

  if (isCustom) {
    const customBadge = document.createElement('span');
    customBadge.className = 'custom-quiz-badge';
    customBadge.textContent = 'Vlastn\u00ED';
    cardTitle.appendChild(document.createTextNode(' '));
    cardTitle.appendChild(customBadge);
  }

  const progress = loadQuizProgress(quiz.id);
  if (progress) {
    const questions = progress.questions;
    const resolvedCount = Object.values(questions).filter(
      (q) => q?.resolved,
    ).length;
    const totalCount = quiz.questions.length;

    const progressBadge = document.createElement('span');
    progressBadge.className = 'progress-quiz-badge';
    progressBadge.textContent = `Rozpracov\u00E1no ${String(resolvedCount)}/${String(totalCount)}`;
    cardTitle.appendChild(document.createTextNode(' '));
    cardTitle.appendChild(progressBadge);
  }

  const cardDesc = document.createElement('p');
  cardDesc.className = 'quiz-card-desc';
  cardDesc.textContent = quiz.description;

  const cardMeta = document.createElement('span');
  cardMeta.className = 'quiz-card-meta';
  cardMeta.textContent = `${String(quiz.questions.length)} ot\u00E1zek`;

  info.appendChild(cardTitle);
  info.appendChild(cardDesc);
  info.appendChild(cardMeta);

  card.appendChild(info);

  // Show best and last result if exists
  const quizResults = allResults.filter((r) => r.quizId === quiz.id);
  if (quizResults.length > 0) {
    const best = quizResults.reduce((a, b) => (a.score > b.score ? a : b));
    const bestPercent = Math.round((best.score / best.totalQuestions) * 100);

    const badgeContainer = document.createElement('div');
    badgeContainer.className = 'quiz-card-badges';

    const bestBadge = document.createElement('span');
    bestBadge.className = 'quiz-card-badge';
    bestBadge.textContent = `Nejlep\u0161\u00ED: ${String(bestPercent)}%`;
    badgeContainer.appendChild(bestBadge);

    const getTime = (r: { completedAt?: number }): number => r.completedAt ?? 0;
    const last = quizResults.reduce((a, b) =>
      getTime(a) > getTime(b) ? a : b,
    );
    const lastPercent = Math.round((last.score / last.totalQuestions) * 100);

    const lastBadge = document.createElement('span');
    lastBadge.className = 'quiz-card-badge quiz-card-badge-last';
    lastBadge.textContent = `Posledn\u00ED: ${String(lastPercent)}%`;
    badgeContainer.appendChild(lastBadge);

    card.appendChild(badgeContainer);
  }

  card.addEventListener('click', () => { onQuizSelect(quiz); });

  return card;
}
