import type { Quiz } from '../types/quiz';
import { remove } from '../storage/local-storage';
import { clearAllProgress } from '../storage/quiz-progress';
import { loadCustomQuizzes, deleteCustomQuiz } from '../storage/custom-quizzes';
import { loadResults, deleteQuizResults } from './results-screen';
import { quizRegistry } from '../content/registry';

/** Callback when user wants to go back. */
export type OnDataBack = () => void;

/** Callback when user wants to edit a custom quiz. */
export type OnEditQuiz = (quiz: Quiz) => void;

/** Reset all quiz results history. */
export function resetResults(): void {
  remove('results');
}

/** Reset everything — results, progress, custom quizzes. */
export function resetAll(): void {
  remove('results');
  clearAllProgress();
  const custom = loadCustomQuizzes();
  for (const quiz of custom) {
    deleteCustomQuiz(quiz.id);
  }
}

/** Render the data management screen. */
export function renderDataManagement(
  container: HTMLElement,
  onBack: OnDataBack,
  onEditQuiz?: OnEditQuiz,
): void {
  container.innerHTML = '';

  const wrapper = document.createElement('div');
  wrapper.className = 'data-management';

  // Header
  const header = document.createElement('header');
  header.className = 'data-header';

  const backBtn = document.createElement('button');
  backBtn.className = 'btn btn-ghost quiz-exit-btn';
  backBtn.textContent = 'Zpět';
  backBtn.addEventListener('click', onBack);

  const title = document.createElement('h2');
  title.className = 'data-title';
  title.textContent = 'Správa dat';

  header.appendChild(backBtn);
  header.appendChild(title);
  wrapper.appendChild(header);

  // Results section
  const resultsSection = document.createElement('section');
  resultsSection.className = 'data-section';

  const resultsTitle = document.createElement('h3');
  resultsTitle.className = 'data-section-title';
  resultsTitle.textContent = 'Výsledky';

  const resetResultsBtn = document.createElement('button');
  resetResultsBtn.className = 'btn btn-ghost data-action-btn';
  resetResultsBtn.textContent = 'Smazat historii výsledků';
  resetResultsBtn.addEventListener('click', () => {
    resetResults();
    showConfirmation(resetResultsBtn, 'Výsledky smazány');
    // Re-render results list
    const resultRows = resultsSection.querySelectorAll('.data-result-row');
    for (const r of resultRows) { r.remove(); }
    if (!resultsSection.querySelector('.data-empty')) {
      const emptyMsg = document.createElement('p');
      emptyMsg.className = 'data-empty';
      emptyMsg.textContent = '\u017D\u00E1dn\u00E9 v\u00FDsledky';
      resultsSection.appendChild(emptyMsg);
    }
  });

  resultsSection.appendChild(resultsTitle);

  // Per-quiz result deletion
  const results = loadResults();
  const quizIdsWithResults = [...new Set(results.map((r) => r.quizId))];

  // Build a title lookup from registry + custom quizzes
  const allQuizzes = [...quizRegistry, ...loadCustomQuizzes()];
  const titleLookup = new Map<string, string>();
  for (const q of allQuizzes) {
    titleLookup.set(q.id, q.title);
  }

  if (quizIdsWithResults.length === 0) {
    const empty = document.createElement('p');
    empty.className = 'data-empty';
    empty.textContent = '\u017D\u00E1dn\u00E9 v\u00FDsledky';
    resultsSection.appendChild(empty);
  } else {
    for (const quizId of quizIdsWithResults) {
      const row = document.createElement('div');
      row.className = 'data-result-row';

      const name = document.createElement('span');
      name.className = 'data-result-name';
      name.textContent = titleLookup.get(quizId) ?? quizId;

      const count = document.createElement('span');
      count.className = 'data-result-count';
      const resultCount = results.filter((r) => r.quizId === quizId).length;
      count.textContent = `${String(resultCount)}\u00D7`;

      const deleteBtn = document.createElement('button');
      deleteBtn.className = 'btn btn-ghost data-result-delete-btn';
      deleteBtn.textContent = 'Smazat';
      deleteBtn.dataset.quizId = quizId;
      deleteBtn.addEventListener('click', () => {
        deleteQuizResults(quizId);
        row.remove();
        // Check if results section is now empty
        if (resultsSection.querySelectorAll('.data-result-row').length === 0) {
          const emptyMsg = document.createElement('p');
          emptyMsg.className = 'data-empty';
          emptyMsg.textContent = '\u017D\u00E1dn\u00E9 v\u00FDsledky';
          resultsSection.appendChild(emptyMsg);
        }
      });

      row.appendChild(name);
      row.appendChild(count);
      row.appendChild(deleteBtn);
      resultsSection.appendChild(row);
    }
  }

  resultsSection.appendChild(resetResultsBtn);
  wrapper.appendChild(resultsSection);

  // Progress section
  const progressSection = document.createElement('section');
  progressSection.className = 'data-section';

  const progressTitle = document.createElement('h3');
  progressTitle.className = 'data-section-title';
  progressTitle.textContent = 'Rozpracované kvízy';

  const clearProgressBtn = document.createElement('button');
  clearProgressBtn.className = 'btn btn-ghost data-action-btn';
  clearProgressBtn.textContent = 'Smazat rozpracované kvízy';
  clearProgressBtn.addEventListener('click', () => {
    clearAllProgress();
    showConfirmation(clearProgressBtn, 'Progres smazán');
  });

  progressSection.appendChild(progressTitle);
  progressSection.appendChild(clearProgressBtn);
  wrapper.appendChild(progressSection);

  // Custom quizzes section
  const customSection = document.createElement('section');
  customSection.className = 'data-section';

  const customTitle = document.createElement('h3');
  customTitle.className = 'data-section-title';
  customTitle.textContent = 'Vlastní kvízy';

  customSection.appendChild(customTitle);

  const customQuizzes = loadCustomQuizzes();
  if (customQuizzes.length === 0) {
    const empty = document.createElement('p');
    empty.className = 'data-empty';
    empty.textContent = 'Žádné vlastní kvízy';
    customSection.appendChild(empty);
  } else {
    for (const quiz of customQuizzes) {
      const row = document.createElement('div');
      row.className = 'data-quiz-row';

      const name = document.createElement('span');
      name.className = 'data-quiz-name';
      name.textContent = quiz.title;

      const actions = document.createElement('div');
      actions.className = 'data-quiz-actions';

      if (onEditQuiz) {
        const editBtn = document.createElement('button');
        editBtn.className = 'btn btn-ghost data-edit-btn';
        editBtn.textContent = 'Upravit';
        editBtn.dataset.quizId = quiz.id;
        editBtn.addEventListener('click', () => {
          onEditQuiz(quiz);
        });
        actions.appendChild(editBtn);
      }

      const deleteBtn = document.createElement('button');
      deleteBtn.className = 'btn btn-ghost data-delete-btn';
      deleteBtn.textContent = 'Smazat';
      deleteBtn.dataset.quizId = quiz.id;
      deleteBtn.addEventListener('click', () => {
        deleteCustomQuiz(quiz.id);
        row.remove();
        // Check if section is now empty
        if (customSection.querySelectorAll('.data-quiz-row').length === 0) {
          const emptyMsg = document.createElement('p');
          emptyMsg.className = 'data-empty';
          emptyMsg.textContent = 'Žádné vlastní kvízy';
          customSection.appendChild(emptyMsg);
        }
      });
      actions.appendChild(deleteBtn);

      row.appendChild(name);
      row.appendChild(actions);
      customSection.appendChild(row);
    }
  }

  wrapper.appendChild(customSection);

  // Reset all
  const dangerSection = document.createElement('section');
  dangerSection.className = 'data-section data-danger';

  const dangerTitle = document.createElement('h3');
  dangerTitle.className = 'data-section-title';
  dangerTitle.textContent = 'Nebezpečná zóna';

  const resetAllBtn = document.createElement('button');
  resetAllBtn.className = 'btn data-reset-all-btn';
  resetAllBtn.textContent = 'Smazat všechna data';
  resetAllBtn.addEventListener('click', () => {
    resetAll();
    showConfirmation(resetAllBtn, 'Vše smazáno');
    // Re-render custom quiz list
    const rows = customSection.querySelectorAll('.data-quiz-row');
    for (const r of rows) { r.remove(); }
    if (!customSection.querySelector('.data-empty')) {
      const emptyMsg = document.createElement('p');
      emptyMsg.className = 'data-empty';
      emptyMsg.textContent = 'Žádné vlastní kvízy';
      customSection.appendChild(emptyMsg);
    }
    // Re-render results list
    const resultRows = resultsSection.querySelectorAll('.data-result-row');
    for (const r of resultRows) { r.remove(); }
    if (!resultsSection.querySelector('.data-empty')) {
      const emptyMsg = document.createElement('p');
      emptyMsg.className = 'data-empty';
      emptyMsg.textContent = '\u017D\u00E1dn\u00E9 v\u00FDsledky';
      resultsSection.appendChild(emptyMsg);
    }
  });

  dangerSection.appendChild(dangerTitle);
  dangerSection.appendChild(resetAllBtn);
  wrapper.appendChild(dangerSection);

  container.appendChild(wrapper);
}

function showConfirmation(btn: HTMLElement, message: string): void {
  const original = btn.textContent;
  btn.textContent = message;
  btn.classList.add('confirmed');
  setTimeout(() => {
    btn.textContent = original;
    btn.classList.remove('confirmed');
  }, 2000);
}
